import{_ as s,o,c as e,a2 as n}from"./chunks/framework.BWuWLRhz.js";const d="/assets/24-plugin-overview@2x.CV-d1EGB.png",u=JSON.parse('{"title":"24 · 插件（Plugins）：把一堆零碎配置一键打包","description":"","frontmatter":{"head":[["meta",{"property":"og:site_name","content":"David Studio AI 编程指南"}]]},"headers":[],"relativePath":"claude-code/24-plugins.md","filePath":"claude-code/24-plugins.md"}'),a={name:"claude-code/24-plugins.md"};function l(p,t,i,r,c,g){return o(),e("div",null,[...t[0]||(t[0]=[n('<h1 id="_24-·-插件-plugins-把一堆零碎配置一键打包" tabindex="-1">24 · 插件（Plugins）：把一堆零碎配置一键打包 <a class="header-anchor" href="#_24-·-插件-plugins-把一堆零碎配置一键打包" aria-label="Permalink to &quot;24 · 插件（Plugins）：把一堆零碎配置一键打包&quot;">​</a></h1><blockquote><p>📚 <strong>系列导航</strong>：上一篇 [23 子代理（Subagents）] 教你亲手造了一个专项小助手。但你有没有发现一个问题——subagent、命令、skill、hook 这些好东西，全是「一个个单独配」的散件。这一篇教你把它们打包成<strong>插件（plugin）</strong>：一键装、一键停，还能直接从「插件市场」拿别人造好的现成全家桶。</p></blockquote><p>兄弟们，今天聊怎么把一堆零碎配置一键打包。说起来，你有没有遇到过这种场景：你辛苦给团队配好了一套「subagent + hook + MCP」，然后某天来了个新同事，你给他讲了半小时——「这个文件放 <code>agents/</code>，那段 hook 加到 <code>settings.json</code> 里，对了还有 <code>.mcp.json</code> 别忘了」——讲完发现他还是漏了一处，跑起来跟你的不一样。这不是谁的问题，散件管理本来就是这样：<strong>配置越分散，口头交代越容易漏</strong>。</p><p>你回头看看前面几篇攒下的家当：第 18 篇写了 <code>CLAUDE.md</code>，第 22 篇配了 MCP server，第 23 篇造了 subagent，中间还穿插着 skill、hook。<strong>每一样单独看都好用，但它们全是散的</strong>——subagent 放 <code>agents/</code>、hook 写在 <code>settings.json</code>、MCP 配在 <code>.mcp.json</code>，分散在好几个文件里。</p><p>问题来了：你在 A 项目辛辛苦苦配好的这一套，换到 B 项目想复用，得一个文件一个文件挨个抄过去。团队里新同事想要你这套配置，你得把目录结构口头讲一遍，还容易漏。<strong>散件管理，就是又累又容易出错。</strong></p><p>说白了，插件就是 Claude Code 给这个问题的官方答案：<strong>把 commands、subagents、skills、hooks、MCP server 这些散件，打成一个能整体分发、能一键启停的包</strong>。这一篇就把「插件是啥、怎么从市场拿现成的、怎么管」一次讲透。</p><p><strong>看完这一篇，你会拿到：</strong></p><ul><li>插件到底打包了哪些东西，以及它和「散装配置」该怎么选，一张表说清</li><li>「插件市场（marketplace）」两步走的逻辑：先加市场、再装插件，命令照抄就能用</li><li>从官方演示市场亲手装一个插件、跑通它带来的命令，全程给预期输出</li><li>插件目录长什么样（<code>plugin.json</code> + 各组件文件夹），自己想打包时照着摆</li><li>装第三方插件前必须过的「信任关」，别把陌生插件当无害软件</li></ul><hr><h2 id="_01-先搞懂-插件到底是个什么东西" tabindex="-1">01 先搞懂：插件到底是个什么东西 <a class="header-anchor" href="#_01-先搞懂-插件到底是个什么东西" aria-label="Permalink to &quot;01 先搞懂：插件到底是个什么东西&quot;">​</a></h2><p>先给结论：<strong>插件就是一个「自包含的文件夹」，把你前面学的那些扩展（skill、subagent、hook、命令、MCP server）打包在一起，能当成一个整体来装、来停、来分发。</strong></p><p>为什么需要它？因为散装配置有三个绕不开的痛点：<strong>跨项目复用麻烦、团队共享靠人肉、版本更新没法追</strong>。你在一个项目里配好的 subagent 加 hook，想搬到另一个项目，只能手动复制粘贴；想分给同事，得把每个文件都说清放哪儿。插件就是把这一整套「装进一个盒子」，盒子整个搬走、整个递给别人就行。</p><p><strong>类比：浏览器扩展商店。</strong> 你想给 Chrome 加广告拦截、加翻译、加截图——不用自己写代码、改配置，去扩展商店点一下「安装」，一整套功能就进来了，不想要了点「移除」就干净卸载。Claude Code 的插件就是这套思路：<strong>逛市场、一键装一整套功能，不用自己一件件手动配</strong>；它把过去散在好几个文件里的扩展，变成商店里一个能直接「装/卸」的条目。</p><p>官方文档把「插件」和「散装配置」的取舍讲得很清楚，我替你浓缩成一张表：</p><table tabindex="0"><thead><tr><th>维度</th><th>散装配置（<code>.claude/</code> 目录）</th><th>插件（plugin）</th></tr></thead><tbody><tr><td><strong>最适合</strong></td><td>单个项目自用、个人工作流、快速试验</td><td>团队/社区共享、跨项目复用、版本化发布</td></tr><tr><td><strong>怎么共享</strong></td><td>手动复制文件给别人</td><td>通过市场，别人 <code>/plugin install</code> 一键装</td></tr><tr><td><strong>skill 名字</strong></td><td>短，如 <code>/hello</code></td><td>带命名空间，如 <code>/my-plugin:hello</code></td></tr><tr><td><strong>能不能版本管理</strong></td><td>不行，改了没法通知用户</td><td>能，设了版本号用户才收到更新</td></tr></tbody></table><p>这张表的判断逻辑就一句话：<strong>自己一个项目随手用，散装就够了；要给别人用、要跨项目搬、要能更新，才上插件</strong>。官方也建议「先用 <code>.claude/</code> 散装快速迭代，准备好共享了再转成插件」——别一上来就为一个一次性配置造插件，那是过度工程。</p><p>这里有个新手最容易迷糊的点，必须先说清：<strong>插件里的 skill 名字永远带「命名空间」</strong>。你在一个叫 <code>my-plugin</code> 的插件里写了个 <code>hello</code> skill，调用时不是 <code>/hello</code>，而是 <code>/my-plugin:hello</code>。</p><blockquote><p>💡 一句话总结：插件就是把 skill、subagent、hook、命令、MCP server 打成一个能整体装卸的盒子；<strong>自用散装就行，要共享、要复用、要更新才打包成插件</strong>。</p></blockquote><hr><h2 id="_02-为什么打成一个包-比散着放强" tabindex="-1">02 为什么打成一个包，比散着放强 <a class="header-anchor" href="#_02-为什么打成一个包-比散着放强" aria-label="Permalink to &quot;02 为什么打成一个包，比散着放强&quot;">​</a></h2><p>上一节讲了「是什么」，这一节补一刀「凭什么值得」——因为光知道概念，你可能还是觉得「我手动复制几个文件也不费事」。</p><p>真正的差距在三个地方，结合具体场景讲，你就懂了。</p><p><strong>第一，跨项目复用。</strong> 设想你常备一套「git 提交工作流」的配置——一个生成规范提交信息的 skill、一个提交前自动跑 lint 的 hook。早期这套是散装的，换一个新项目就得把 <code>skills/</code> 和 <code>settings.json</code> 里那段挨个抄。一旦抄漏了 hook 那段，新项目里提交前没跑 lint，就可能混进去一个格式错误。<strong>打成插件之后，新项目里一句 <code>/plugin install</code> 就齐活了，再不会漏。</strong></p><p><strong>第二，团队共享。</strong> 散装配置分享给同事，基本靠「你把这个文件夹拷过去，放到 <code>.claude/agents/</code> 下，然后那个 hook 记得加到 settings 里」——一通口头交代，对方十有八九配错。插件不一样：<strong>你把它发到一个市场（哪怕是公司内部的私有仓库），同事一条命令装好，配置完全一致</strong>，不存在「我这能跑你那不行」。</p><p><strong>第三，版本更新。</strong> 这是散装最致命的短板。散装配置改了，用过的人根本不知道，只能你挨个通知。插件可以带版本号，<strong>你发新版，用户更新时就自动拿到最新的</strong>；官方还专门做了「自动更新」——官方市场默认开着，第三方市场默认关着（这设计很合理，自己人的更新可以自动收，外人的得你主动同意）。</p><p><strong>类比：手机 App 和它在应用商店的关系。</strong> 你装了个 App，它出新版本，应用商店推给你「有更新」，你点一下就升级了，不用自己重新下安装包。插件之于市场，就是 App 之于应用商店——<strong>装是一键装，更新是顺着市场流下来的，不用你手动搬运</strong>。</p><p>对照一下散装和插件在这三件事上的差距：</p><table tabindex="0"><thead><tr><th>你要干的事</th><th>❌ 散装配置</th><th>✅ 插件</th></tr></thead><tbody><tr><td>搬到新项目</td><td>手动复制每个文件，容易漏</td><td><code>/plugin install</code> 一句</td></tr><tr><td>给同事用</td><td>口头交代放哪、怎么配</td><td>发市场，对方一条命令装</td></tr><tr><td>推送更新</td><td>没法通知，只能人肉喊</td><td>带版本号，用户自动/手动更新</td></tr></tbody></table><p>说句实话，<strong>单人单项目，插件的好处你感受不深；一旦人多了、项目多了，散装就开始拖后腿</strong>。我自己也是带团队之后才彻底转向插件的——之前给新人配环境，得拉着人对着屏幕一个文件一个文件讲「这个放 <code>agents/</code>、那个 hook 加到 settings 里」，一上午能折腾掉小半天，还总有人漏一处；打成插件挂到内部仓库之后，新人就一条命令装完，配置跟我这边一模一样，再没出过「我这能跑你那不行」。</p><blockquote><p>💡 一句话总结：插件的真正价值在「规模」——<strong>跨项目复用、团队共享、版本更新</strong>这三件事，散装全靠人肉，插件全是一条命令；人和项目越多，这差距越大。</p></blockquote><hr><h2 id="_03-插件市场-先加「商店」-再装「应用」" tabindex="-1">03 插件市场：先加「商店」，再装「应用」 <a class="header-anchor" href="#_03-插件市场-先加「商店」-再装「应用」" aria-label="Permalink to &quot;03 插件市场：先加「商店」，再装「应用」&quot;">​</a></h2><p>知道了插件是什么，下一个问题是：<strong>别人造好的插件，我从哪儿拿？</strong> 答案是「插件市场（marketplace）」。</p><p><strong>这里有个全篇最关键、新手最容易卡壳的认知：用市场是「两步」，不是「一步」。</strong></p><ul><li><strong>第一步：加市场。</strong> 把一个市场「注册」给 Claude Code，让它能浏览这个市场里有哪些插件。<strong>注意，这一步一个插件都没装</strong>，只是让你看得到货架。</li><li><strong>第二步：装插件。</strong> 在货架上挑你要的，单独安装。</li></ul><p><strong>类比：给手机装一个新的「应用商店」。</strong> 你手机上除了自带商店，还可以装第三方应用商店——但「装好这个商店」不等于「装好了里面的 App」。商店只是让你能进去逛、能看到它的全部收藏，<strong>具体要哪个 App，还得你自己点进去单独下载</strong>。插件市场就是这么个「应用商店」：加进来是让你能逛，装哪个插件是另一码事。</p><p>想清楚这个「两步」，下面的命令就全顺了。先看加市场——官方给了好几种来源，最常用的是从 GitHub 加：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/plugin marketplace add owner/repo</span></span></code></pre></div><p>把 <code>owner/repo</code> 换成实际的 GitHub 仓库名就行（比如官方演示市场是 <code>anthropics/claude-code</code>）。除了 GitHub，市场还能从 Git URL（GitLab、Bitbucket、自托管都行）、本地路径、远程 URL 加，写法官方文档都列了，新手记住 GitHub 这种最常用的即可。</p><p>加完市场，装插件用这条：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/plugin install plugin-name@marketplace-name</span></span></code></pre></div><p><code>@</code> 后面跟的是市场名，意思是「从这个市场装这个插件」。比如从官方市场装 GitHub 集成：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/plugin install github@claude-plugins-official</span></span></code></pre></div><p>这里要单独点名<strong>官方自带的那个市场</strong>：<code>claude-plugins-official</code>。<strong>它不用你手动加——你一启动 Claude Code 它就在了</strong>，里面是 Anthropic 精选的一批插件（GitHub、GitLab、Slack、Figma、Sentry 这些外部集成，还有代码智能的 LSP 插件、安全审查插件等）。所以你想装官方插件，跳过「加市场」那步，直接 <code>install</code> 就行。</p><blockquote><p>💡 一句话总结：用市场永远是「先加市场、再装插件」两步——<code>/plugin marketplace add</code> 加货架、<code>/plugin install xxx@市场名</code> 下单；<strong>唯独官方市场 <code>claude-plugins-official</code> 自带，开箱就能直接装</strong>。</p></blockquote><hr><h2 id="_04-三个市场-分别是干嘛的" tabindex="-1">04 三个市场，分别是干嘛的 <a class="header-anchor" href="#_04-三个市场-分别是干嘛的" aria-label="Permalink to &quot;04 三个市场，分别是干嘛的&quot;">​</a></h2><p>上一节出现了好几个市场名，新手容易搞混。这一节把官方维护的三个市场摆清楚，你以后看到名字就知道是谁。</p><p><strong>类比：同一个城市里三家不同定位的商场。</strong> 一家是品牌直营旗舰店（货都是官方精挑的），一家是开放入驻的大卖场（第三方来摆摊，但进场前过了安检），还有一家是临时的样板展厅（专门摆样品给你看效果）。Claude Code 这三个官方市场正好对上：</p><table tabindex="0"><thead><tr><th>市场</th><th>加它的命令</th><th>定位</th><th>里面是啥</th></tr></thead><tbody><tr><td><code>claude-plugins-official</code>（官方）</td><td>自带，无需添加</td><td>官方精选</td><td>Anthropic 挑过的插件，最稳</td></tr><tr><td><code>claude-community</code>（社区）</td><td><code>/plugin marketplace add anthropics/claude-plugins-community</code></td><td>第三方提交、过了自动审查</td><td>社区贡献的插件，每个固定到具体提交</td></tr><tr><td><code>claude-code-plugins</code>（演示）</td><td><code>/plugin marketplace add anthropics/claude-code</code></td><td>官方放的示例</td><td>展示插件能力的样板插件</td></tr></tbody></table><p>几个要点说清楚：</p><p><strong>官方市场最稳但不开放申请。</strong> Anthropic 自己决定收哪些插件，里面的东西经过精选，<strong>踩坑概率最低</strong>。你日常想要的大路货——GitHub 集成、各语言的 LSP、安全审查——基本都在这儿。</p><p><strong>社区市场是开放的，但有门槛。</strong> 第三方插件提交后，要过 Anthropic 的自动验证和安全筛选才进得来，而且每个插件都被「固定到某次具体提交」——意思是你装的就是审查时那个版本，作者不能偷偷换内容。<strong>它要手动加</strong>，加完用 <code>claude-community</code> 这个名字装。</p><p><strong>演示市场是用来学的。</strong> 它放的是「展示插件系统能做什么」的样板，下一节的动手实验就拿它练手。<strong>它也要手动加</strong>。</p><p>建议的取用顺序：<strong>官方市场优先，官方没有的再去社区市场找，找到了先看主页和它要的权限再装</strong>。演示市场一般只在教学或试水时用——它的定位就是样板，不是给你天天用的生产插件。</p><blockquote><p>💡 一句话总结：官方市场自带最稳、社区市场要手动加但过了安检、演示市场是学习样板；<strong>日常先翻官方，缺货再去社区，演示拿来练手</strong>。</p></blockquote><hr><h2 id="_05-装一个插件-到底装进来了什么" tabindex="-1">05 装一个插件，到底装进来了什么 <a class="header-anchor" href="#_05-装一个插件-到底装进来了什么" aria-label="Permalink to &quot;05 装一个插件，到底装进来了什么&quot;">​</a></h2><p><code>/plugin install</code> 一敲，到底有什么东西进了你的环境？这一节讲清楚，免得你装完一脸懵「然后呢，我怎么用它」。</p><p>一个插件可能带这几类组件进来，<strong>每一类的「触发方式」不一样</strong>，这是关键：</p><table tabindex="0"><thead><tr><th>组件</th><th>装进来后怎么用</th></tr></thead><tbody><tr><td><strong>Skills / Commands</strong></td><td>变成 <code>/插件名:skill名</code> 这种命名空间命令，你手动敲、或 Claude 自动调</td></tr><tr><td><strong>Subagents</strong></td><td>出现在 <code>/agents</code> 列表里，Claude 按任务自动派、你也能手动点</td></tr><tr><td><strong>Hooks</strong></td><td>在对应事件（如改文件后）自动触发，不用你管</td></tr><tr><td><strong>MCP server</strong></td><td>自动启动，它的工具混进 Claude 的工具箱里直接能用</td></tr><tr><td><strong>LSP server</strong></td><td>给 Claude 实时代码智能（跳转定义、查引用、即时报错），需另装语言服务器二进制</td></tr></tbody></table><p>看出来没？<strong>有的是「你主动喊」（skill、命令），有的是「它自动干」（hook、MCP、LSP）</strong>。所以装完一个插件，你得知道它到底带了哪几类东西，才知道怎么用它。</p><p>好消息是，<strong>新版 Claude Code 在你装之前就把这些列给你看</strong>。在 <code>/plugin</code> 界面里点开一个插件的详情，会有个「<strong>将安装</strong>」区块，列出这个插件带的命令、agents、skills、hooks、MCP 和 LSP server；还会给一个「<strong>上下文成本</strong>」估算——告诉你这插件每轮大概往你的上下文窗口塞多少 token。</p><p>这个「上下文成本」得多说一句，<strong>它很重要</strong>。回想第 19 篇讲的上下文管理：插件带的每个组件，都会占掉你工作台的一块地方。装太多插件，等于还没开始干活，上下文就被各种 skill 说明、MCP 工具定义占掉一大截。<strong>装插件前一定要看这个估算，几百 token 的无所谓，上千的得掂量「我是不是真用得上」</strong>。装一堆用不上的插件白占上下文，是新手常犯的浪费。</p><p>还有个细节：<strong>装完插件，记得运行 <code>/reload-plugins</code> 让它生效</strong>，不用重启 Claude Code。会话中途装、停、启用插件，都靠这条命令刷新：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/reload-plugins</span></span></code></pre></div><p>跑完它会告诉你当前加载了几个插件、几个 skill、几个 agent、几个 hook、几个插件 MCP server 和 LSP server。</p><blockquote><p>💡 一句话总结：插件带进来的组件分「你主动喊」（skill/命令）和「它自动干」（hook/MCP/LSP）两类；<strong>装前在详情里看「将安装」清单和上下文成本，装后 <code>/reload-plugins</code> 生效</strong>。</p></blockquote><p><img src="'+d+`" alt="插件市场两步走与插件打包的五类组件"></p><p>这张图把本篇的两条主线画在一起：左边是「加市场 → 装插件」的两步流程，右边是一个插件盒子打包的五类组件（skill、subagent、hook、MCP server、LSP server），以及它们装进来后分别是「你主动喊」还是「它自动干」。</p><hr><h2 id="_06-动手-加一个市场、装一个插件、用起来" tabindex="-1">06 动手：加一个市场、装一个插件、用起来 <a class="header-anchor" href="#_06-动手-加一个市场、装一个插件、用起来" aria-label="Permalink to &quot;06 动手：加一个市场、装一个插件、用起来&quot;">​</a></h2><p>光看不练假把式。下面带你<strong>从官方演示市场加市场、装一个真插件、跑通它带来的命令</strong>，全程不依赖任何复杂环境，跟着抄就行。我们装的是官方文档点名的 <code>commit-commands</code>——一个给 git 工作流加 skill 的插件。</p><p><strong>第一步：启动 Claude Code，加演示市场</strong></p><p>随便进一个目录启动 Claude Code：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span></span></code></pre></div><p>进去后在输入框敲（这是「两步」里的第一步——加市场）：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/plugin marketplace add anthropics/claude-code</span></span></code></pre></div><p><strong>预期</strong>：Claude Code 下载这个市场的目录，提示市场添加成功。此时你的「货架」上有货了，但<strong>还没装任何插件</strong>。</p><p><strong>第二步：打开插件管理器逛一逛</strong></p><p>敲：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/plugin</span></span></code></pre></div><p><strong>预期</strong>：弹出一个带四个标签页的界面——<strong>发现 / 已安装 / 市场 / 错误</strong>，用 <code>Tab</code> 键来回切（<code>Shift+Tab</code> 往回切）。切到「<strong>发现</strong>」标签，能看到你刚加的演示市场里那些样板插件。<strong>看到 <code>commit-commands</code> 在列表里 = 市场加对了。</strong></p><p><strong>第三步：装 <code>commit-commands</code> 插件</strong></p><p>你可以在界面里点它选安装范围，也可以直接命令行装（这是「两步」里的第二步）：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/plugin install commit-commands@claude-code-plugins</span></span></code></pre></div><p>注意 <code>@</code> 后面是 <code>claude-code-plugins</code>——这是这个演示市场的<strong>内部名字</strong>（不是你加市场时写的 <code>anthropics/claude-code</code>，那是仓库地址）。装的时候它会让你选范围：</p><ul><li><strong>用户范围</strong>（默认）：所有项目里你自己都能用</li><li><strong>项目范围</strong>：装进 <code>.claude/settings.json</code>，这个仓库的所有协作者都能用</li><li><strong>本地范围</strong>：只在这个仓库、只有你自己能用</li></ul><p>先选默认的「用户范围」即可。</p><p><strong>预期</strong>：终端提示插件安装成功，可能还会列出它附带自动装了哪些依赖。</p><p><strong>第四步：让插件生效，看它带来的命令</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/reload-plugins</span></span></code></pre></div><p><strong>预期</strong>：Claude Code 重新加载，输出当前加载的插件、skill、agent、hook 以及插件 MCP server 和 LSP server 数量。因为 <code>commit-commands</code> 的 skill 带命名空间，它提供的是像 <code>/commit-commands:commit</code> 这样的命令。</p><p><strong>第五步：用起来——亲眼看插件的 skill 跑活</strong></p><p>先在当前目录随便改个文件制造一点改动（比如新建一个文本文件），然后敲：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/commit-commands:commit</span></span></code></pre></div><p><strong>预期</strong>：这个 skill 会帮你<strong>暂存改动、生成一条提交信息、创建提交</strong>。看到它走完这套 git 提交流程，<strong>说明插件不光装上了，它带的 skill 真的能用了</strong>——这就是「装一个插件、白捡一套现成工作流」的完整体感。</p><blockquote><p>⚠️ 如果第五步敲 <code>/commit-commands:commit</code> 提示找不到命令，先确认你第四步跑了 <code>/reload-plugins</code>；还不行就 <code>/plugin</code> 进「错误」标签看加载报错。</p></blockquote><p>跑通这五步，你就把「加市场 → 装插件 → 生效 → 用起来」这条完整链路亲手验证了一遍。<strong>以后装任何插件，本质都是这套流程。</strong></p><blockquote><p>💡 一句话总结：加市场（<code>marketplace add</code>）→ 装插件（<code>install</code>）→ 生效（<code>/reload-plugins</code>）→ 用命名空间命令——<strong>亲手把 <code>commit-commands</code> 跑通一遍，比记十条命令都管用</strong>。</p></blockquote><hr><h2 id="_07-想自己打包-先认识插件的目录长相" tabindex="-1">07 想自己打包？先认识插件的目录长相 <a class="header-anchor" href="#_07-想自己打包-先认识插件的目录长相" aria-label="Permalink to &quot;07 想自己打包？先认识插件的目录长相&quot;">​</a></h2><p>前面全是「用别人的插件」，但你迟早会想「我能不能把自己那套配置也打成插件」。这一节不教你从零造（那是单独一篇的量），只带你<strong>认住插件的目录长什么样</strong>，做到看得懂、心里有数。</p><p>一个插件的核心就两部分：<strong>一个「身份证」文件 + 各组件的文件夹</strong>。</p><p><strong>身份证</strong>就是 <code>.claude-plugin/plugin.json</code>，它声明这个插件的名字、描述、版本：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;my-first-plugin&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;description&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;A greeting plugin to learn the basics&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;version&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1.0.0&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>其中 <code>name</code> 最关键——<strong>它就是 skill 的命名空间前缀</strong>。这个插件里的 skill 会变成 <code>/my-first-plugin:xxx</code>。<code>version</code> 是可选的，但<strong>设了版本号用户才会在你更新时收到更新</strong>，所以发布时记得每次发新版就提一下版本号。</p><p><strong>各组件的文件夹</strong>就摆在插件根目录下，按类型分门别类。官方的目录约定我整理成一张表，照着摆就对：</p><table tabindex="0"><thead><tr><th>你想加什么</th><th>放到哪个目录</th></tr></thead><tbody><tr><td>skill</td><td><code>skills/&lt;名字&gt;/SKILL.md</code></td></tr><tr><td>subagent</td><td><code>agents/</code></td></tr><tr><td>hook</td><td><code>hooks/hooks.json</code></td></tr><tr><td>MCP server</td><td>根目录的 <code>.mcp.json</code></td></tr><tr><td>LSP server</td><td>根目录的 <code>.lsp.json</code></td></tr></tbody></table><p>整个插件摆起来大概长这样：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>my-first-plugin/</span></span>
<span class="line"><span>├── .claude-plugin/</span></span>
<span class="line"><span>│   └── plugin.json        ← 身份证，只有它放这儿</span></span>
<span class="line"><span>├── skills/</span></span>
<span class="line"><span>│   └── hello/</span></span>
<span class="line"><span>│       └── SKILL.md</span></span>
<span class="line"><span>├── agents/</span></span>
<span class="line"><span>│   └── reviewer.md</span></span>
<span class="line"><span>└── hooks/</span></span>
<span class="line"><span>    └── hooks.json</span></span></code></pre></div><p>这里有个<strong>官方反复强调、新手必踩的坑</strong>，我替你画重点：</p><blockquote><p><strong>常见错误</strong>：不要将 <code>commands/</code>、<code>agents/</code>、<code>skills/</code> 或 <code>hooks/</code> 放在 <code>.claude-plugin/</code> 目录内。只有 <code>plugin.json</code> 应该在 <code>.claude-plugin/</code> 内。所有其他目录必须在插件根级别。</p></blockquote><p>说白了：<strong><code>.claude-plugin/</code> 这个文件夹里只准放 <code>plugin.json</code> 一个东西</strong>，其他组件文件夹全部摆在插件根目录下，跟 <code>.claude-plugin/</code> 平级。这个坑我第一次打包就踩了——图省事顺手把 <code>skills/</code> 也塞进了 <code>.claude-plugin/</code>，结果插件明明加载成功、<code>/reload-plugins</code> 也没报错，可那个 skill 死活不出现。我对着 plugin.json 检查了半天名字、版本、命名空间，全对，最后才反应过来是目录摆错位置了。挪出来跟 <code>plugin.json</code> 平级，立马就好。</p><p>你可能注意到，这套目录结构跟第 13 篇讲的 <code>.claude/</code> 项目结构、第 23 篇的 <code>agents/</code>、第 22 篇的 <code>.mcp.json</code> 几乎一模一样。<strong>这不是巧合</strong>——插件本质就是「把你散在 <code>.claude/</code> 各处的那些配置，按同样的格式收进一个独立文件夹」。所以官方才说散装配置能「转换成插件」，因为格式是相通的，搬过去就行。</p><p>想真正动手测自己打的包，官方给了个不用装市场的快捷办法——启动时用 <code>--plugin-dir</code> 直接加载本地插件目录：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --plugin-dir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./my-first-plugin</span></span></code></pre></div><p>这个标志专门给开发测试用，改完插件跑 <code>/reload-plugins</code> 就能看到效果，不用走「发市场再安装」那一整套。</p><blockquote><p>💡 一句话总结：插件 = <code>.claude-plugin/plugin.json</code>（身份证，<code>name</code> 定命名空间）+ 根目录下的各组件文件夹；<strong>记死那条铁律——<code>.claude-plugin/</code> 里只放 <code>plugin.json</code>，别的文件夹全摆根目录</strong>。</p></blockquote><hr><h2 id="_08-装第三方插件-先过「信任关」" tabindex="-1">08 装第三方插件，先过「信任关」 <a class="header-anchor" href="#_08-装第三方插件-先过「信任关」" aria-label="Permalink to &quot;08 装第三方插件，先过「信任关」&quot;">​</a></h2><p>这是全篇最该慎重的一节，<strong>也是新手最容易掉以轻心的地方</strong>：插件不是无害的小工具，<strong>它能用你的权限在你机器上执行任意代码</strong>。</p><p>回想第 21 篇讲的安全边界——那一篇的判断力，到了插件这儿一样适用，甚至更要紧。官方把话说得很重：</p><blockquote><p>插件和市场是高度受信任的组件，可以使用您的用户权限在您的机器上执行任意代码。仅从您信任的来源安装插件和添加市场。</p></blockquote><p>这是什么意思？<strong>一个插件里可能带 hook（自动跑脚本）、带 MCP server（自动启动的程序）、带 <code>bin/</code> 里的可执行文件</strong>。你装它、启用它，这些东西就在你的权限下跑起来了——它能读你的文件、能联网、能执行命令，<strong>和你自己敲命令的权限一样大</strong>。装一个来路不明的插件，约等于把陌生人的脚本直接在你电脑上运行。</p><p><strong>类比：从陌生网站下载一个 <code>.exe</code> 双击运行。</strong> 你不会随便从一个没听说过的网站下个可执行文件就双击吧？因为它一旦跑起来，能干的事跟你本人一样多。装第三方插件就是这个性质——<strong>来源可信不可信，是装之前必须先回答的问题</strong>，不能图省事直接装。</p><p>所以这里给你三条「装第三方插件前」的自检，值得当成硬规矩：</p><table tabindex="0"><thead><tr><th>检查项</th><th>怎么做</th></tr></thead><tbody><tr><td><strong>来源可信吗</strong></td><td>优先官方市场；社区市场的看作者、看主页；陌生个人仓库的，没把握就别装</td></tr><tr><td><strong>它带了什么</strong></td><td>装前在 <code>/plugin</code> 详情的「将安装」里看清楚带不带 hook / MCP / 可执行文件</td></tr><tr><td><strong>范围给到哪</strong></td><td>不确定的先用「本地范围」试，别一上来就「用户范围」铺到所有项目</td></tr></tbody></table><p>几个能让你稍微安心的官方设计：<strong>社区市场的插件过了自动验证和安全筛选，且固定到具体提交</strong>（作者没法偷换内容）；<strong>官方市场是 Anthropic 精选</strong>，最省心。但这些都不能替代你自己的判断——<strong>核心还是那句「只从你信任的来源装」</strong>。</p><p>一套稳妥的实践：<strong>官方市场的插件直接装；社区市场的，先去它主页扫一眼是谁、干什么的、要哪些权限，再决定；陌生来源的私人插件，除非你能看懂它的代码，否则一律不碰</strong>。说句实话，插件这东西方便归方便，但「方便」和「安全」从来是要你自己拿捏的——<strong>别把一键安装的顺滑，当成了它无害的证据</strong>。</p><blockquote><p>💡 一句话总结：插件能用你的权限跑任意代码，装第三方的等于在你机器上运行陌生人的脚本；<strong>装前三查——来源可信吗、带了啥、范围给到哪，官方市场最稳，陌生来源宁可不装</strong>。</p></blockquote><hr><h2 id="_09-小结" tabindex="-1">09 小结 <a class="header-anchor" href="#_09-小结" aria-label="Permalink to &quot;09 小结&quot;">​</a></h2><p>这一篇我们把 Claude Code 的「插件」从概念捋到动手——<strong>它本质就是把你前面学的那些散件，打成一个能整体装卸、能分发、能更新的盒子</strong>。</p><p>把核心要点串起来回顾：</p><table tabindex="0"><thead><tr><th>你要做的事</th><th>用什么</th><th>关键点</th></tr></thead><tbody><tr><td>理解插件是什么</td><td>plugin = 散件打包盒</td><td>装 skill/subagent/hook/MCP/LSP，自用散装、共享才打包</td></tr><tr><td>拿别人的插件</td><td>插件市场</td><td>两步：<code>marketplace add</code> 加市场 → <code>install</code> 装插件</td></tr><tr><td>认市场</td><td>三个官方市场</td><td>官方自带最稳、社区要手动加、演示拿来练</td></tr><tr><td>让插件生效</td><td><code>/reload-plugins</code></td><td>中途装/停都靠它刷新，不用重启</td></tr><tr><td>看清装了啥</td><td><code>/plugin</code> 详情</td><td>「将安装」清单 + 上下文成本，装前先看</td></tr><tr><td>自己打包</td><td><code>plugin.json</code> + 组件文件夹</td><td><code>.claude-plugin/</code> 里只放 <code>plugin.json</code></td></tr><tr><td>装第三方</td><td>信任三查</td><td>能跑任意代码，只从可信来源装</td></tr></tbody></table><p><strong>你现在应该能：</strong> 看懂插件和散装配置该怎么选、用「加市场 → 装插件 → <code>/reload-plugins</code>」三步从市场拿到现成功能、看懂插件详情里的「将安装」清单和上下文成本、认住插件的目录长相，并且清楚装第三方插件前必须先过信任关。<strong>这套能力让你不用什么都自己从零配——市场上现成的全家桶，拿来即用。</strong></p><p>从第 18 篇到这一篇，你已经把 Claude Code 的「扩展工具箱」配齐了：<code>CLAUDE.md</code>、MCP、subagent、skill、hook，最后用插件把它们打包统管。<strong>工具，到这儿算是装齐了。</strong></p><hr><p>下一篇 <strong>25「记忆系统（memory）」</strong>——工具装齐了，但你有没有发现一个别扭的地方：每开一个新会话，Claude 又是一张白纸，你上次告诉它的偏好、这个项目的关键事实，它转头就忘。下一篇就聊<strong>怎么让 Claude 跨会话「记住」你</strong>——记住你爱用的技术栈、记住项目的硬规矩，不用每次从头交代。想想看：如果它能像个共事久了的老搭档一样，开口就知道你的习惯，是不是省事多了？</p>`,140)])])}const k=s(a,[["render",l]]);export{u as __pageData,k as default};
